async (params, browser) => {
  // Open Google Flights Explore
  await browser.open(`https://www.google.com/travel/explore?q=flights+from+${params.origin}`)

  // Wait for explore results
  await browser.waitForSelector('div.tsUJMc, div[role=\'listbox\'], a[href*=\'/travel/flights\']', 20000)

  // Let map and results load
  await browser.wait(4000)

  // Scroll to see destination list
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(2000)

  // Extract explore destinations
  const explore_results = await browser.evaluate(`const destinations = []; const cards = document.querySelectorAll('div.tsUJMc, div[role="option"], a[href*="/travel/flights"]'); const seen = new Set(); cards.forEach((card, i) => { if (destinations.length >= 20) return; const nameEl = card.querySelector('h3, div.n4HaVc, div[class*="title"]'); const priceEl = card.querySelector('div.f4F6oe, span[data-gs], span[aria-label*="$"], span[aria-label*="EUR"]'); const datesEl = card.querySelector('div.mMKuie, div[class*="date"]'); const imgEl = card.querySelector('img'); const linkEl = card.querySelector('a[href]'); const name = nameEl ? nameEl.textContent.trim() : ''; if (!name || seen.has(name)) return; seen.add(name); destinations.push({ destination: name, price: priceEl ? priceEl.textContent.trim() : '', dates: datesEl ? datesEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); }); return { origin: params.origin, destination_count: destinations.length, destinations: destinations, url: window.location.href }`)

  return explore_results
}
